# Load existing all_flows.json (has full metadata for ~22 flows)
with open("/home/user/skills/audit_output/intermediate/all_flows.json") as f:
    all_flows = json.load(f)

print(f"Existing flows with full metadata: {len(all_flows)}")

# Build skeleton records for all flows from TOOLING_DATA
count_new = 0
for name, info in TOOLING_DATA.items():
    if name not in all_flows:
        # Create skeleton record
        all_flows[name] = {
            "fullName": name,
            "processType": info["processType"],
            "description": info.get("description", ""),
            "status": "Active",
            "start": {"connector": {}},
            "variables": [],
            "assignments": [],
            "decisions": [],
            "loops": [],
            "recordLookups": [],
            "recordCreates": [],
            "recordUpdates": [],
            "recordDeletes": [],
            "screens": [],
            "subflows": [],
            "actionCalls": [],
            "constants": [],
            "formulas": [],
            "choices": [],
            "textTemplates": [],
        }
        count_new += 1
    else:
        # Update processType and description if missing
        if not all_flows[name].get("processType"):
            all_flows[name]["processType"] = info["processType"]
        if not all_flows[name].get("description") and info.get("description"):
            all_flows[name]["description"] = info["description"]

# Save
with open("/home/user/skills/audit_output/intermediate/all_flows.json", "w") as f:
    json.dump(all_flows, f)

print(f"Added {count_new} skeleton records")
print(f"Total flows now: {len(all_flows)}")
print(f"Flow types: ")
from collections import Counter
types = Counter(f.get("processType", "Unknown") for f in all_flows.values())
for t, c in types.most_common():
    print(f"  {t}: {c}")
